    }
  });
});

import { chmod, mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import {
  type ConfigPatchRegistryEntry,
  type FileWriteRegistryEntry,
  type FrontmatterEmitRegistryEntry,
  type Registry,
  type RegistryEntry,
  RegistrySchema,
  type SkillDirRegistryEntry,
} from "../schemas/registry.ts";
import type { AgentId } from "../types.ts";

export type { RegistryEntry } from "../schemas/registry.ts";

const REGISTRY_DIR = ".inception-engine";
const REGISTRY_FILE = "registry.json";

export interface RegistryPersistence {
  load(home: string): Promise<Registry>;
  save(home: string, registry: Registry): Promise<void>;
}

export type VerifyExpected =
  | { kind: "skill-dir"; source: string; skill: string; agent: AgentId }
  | { kind: "file-write"; source: string; skill: string; agent: AgentId }
  | { kind: "config-patch"; skill: string; agent: AgentId };

export function registryPath(home: string): string {
  return path.join(home, REGISTRY_DIR, REGISTRY_FILE);
}

async function loadRegistry(home: string): Promise<Registry> {
  try {
    const content = await readFile(registryPath(home), "utf-8");
    const parsed = JSON.parse(content);
    const result = RegistrySchema.safeParse(parsed);
    return result.success ? result.data : emptyRegistry();
  } catch {
    return emptyRegistry();
  }
}

async function saveRegistry(home: string, registry: Registry): Promise<void> {
  const dir = path.join(home, REGISTRY_DIR);
  await mkdir(dir, { recursive: true });
  const filePath = registryPath(home);
  await writeFile(filePath, `${JSON.stringify(registry, null, 2)}\n`);
  await setFilePermissions(filePath);
}

export const defaultRegistryPersistence: RegistryPersistence = {
  load: loadRegistry,
  save: saveRegistry,
};

/**
 * Ensure the file is not world-writable regardless of umask.
 * On Windows, the OS inherits ACLs from the parent directory — no-op is correct.
 */
async function setFilePermissions(filePath: string): Promise<void> {
  if (process.platform !== "win32") {
    await chmod(filePath, 0o644);
  }
}

function emptyRegistry(): Registry {
  return { version: 1, deployments: {} };
}

export type RegisterEntry =
  | Omit<SkillDirRegistryEntry, "deployed">
  | Omit<FileWriteRegistryEntry, "deployed">
  | Omit<ConfigPatchRegistryEntry, "deployed">
  | Omit<FrontmatterEmitRegistryEntry, "deployed">;

function surfaceIdForEntry(entry: RegisterEntry): string {
  return entry.surfaceId ?? `${entry.kind}:${entry.agent}:${entry.skill}`;
}

export async function registerDeployment(
  home: string,
  targetPath: string,
  entry: RegisterEntry,
  persistence: RegistryPersistence = defaultRegistryPersistence,
): Promise<void> {
  const registry = await persistence.load(home);
  const surfaceId = surfaceIdForEntry(entry);
  for (const migratedTarget of entry.migratedFrom ?? []) {
    if (migratedTarget === targetPath) continue;
    const existing = registry.deployments[migratedTarget];
    if (existing?.surfaceId === surfaceId) {
      delete registry.deployments[migratedTarget];
    }
  }
  registry.deployments[targetPath] = {
    ...entry,
    surfaceId,
    deployed: new Date().toISOString(),
  } as RegistryEntry;
  await persistence.save(home, registry);
}

export async function unregisterDeployment(
  home: string,
  targetPath: string,
  persistence: RegistryPersistence = defaultRegistryPersistence,
): Promise<void> {
  const registry = await persistence.load(home);
  if (!(targetPath in registry.deployments)) return;
  delete registry.deployments[targetPath];
  await persistence.save(home, registry);
}

export async function lookupDeployment(
  home: string,
  targetPath: string,
  persistence: RegistryPersistence = defaultRegistryPersistence,
): Promise<RegistryEntry | null> {
  const registry = await persistence.load(home);
  return registry.deployments[targetPath] ?? null;
}

export async function verifyDeployment(
  home: string,
  targetPath: string,
  expected: VerifyExpected,
  persistence: RegistryPersistence = defaultRegistryPersistence,
): Promise<RegistryEntry | null> {
  const entry = await lookupDeployment(home, targetPath, persistence);
  if (!entry) return null;
  if (entry.kind !== expected.kind) return null;
  if (entry.skill !== expected.skill) return null;
  if (entry.agent !== expected.agent) return null;
  if (
    (expected.kind === "skill-dir" || expected.kind === "file-write") &&
    (entry.kind === "skill-dir" || entry.kind === "file-write") &&
    entry.source !== expected.source
  ) {
    return null;
  }
  return entry;
}

import type { AgentId } from "./schemas/manifest.ts";

export type {
  AgentDefinitionEntry,
  AgentId,
  ConfigEntry,
  FileEntry,
  Manifest,
  SkillEntry,
} from "./schemas/manifest.ts";

export interface AgentPaths {
  posix: string[];
  windows: string[];
}

export type Confidence = "documented" | "implementation-only" | "provisional";

export type CapabilityKind =
  | "skills"
  | "mcpServers"
  | "agentRules"
  | "permissions"
  | "agentDefinitions";

export interface SupportedAgentSurface {
  status: "supported";
  /**
   * Declares how this agent relates to the surface:
   * - "agent-specific" (default when absent): the agent owns this surface
   *   independently and deploy emits a normal action.
   * - "native": the agent reads this surface autonomously without any deploy
   *   action from inception-engine; no action is emitted.
   * - "shared-via": this agent rides another agent's deployment. When the
   *   primary agent (`via`) is also in the target list, deploy skips this
   *   agent's action (the primary writes the shared file). When the primary
   *   is absent, a guidance warning is emitted instead.
   */
  surfaceKind?:
    | { kind: "agent-specific" }
    | { kind: "native" }
    | {
        kind: "shared-via";
        via: AgentId;
        /**
         * When true, this agent cannot deploy to the surface independently —
         * the primary agent (`via`) must also be in the target list. If the
         * primary is absent, a guidance warning is emitted and no action is
         * generated. When false or absent, the agent can deploy to the surface
         * on its own if the primary is not present.
         */
        requiresPrimary?: boolean;
      };
  path: AgentPaths;
  schemaLabel: string;
  // Override the top-level key used when patching a JSON config file.
  // Defaults to "mcpServers" when absent. Allows agents like OpenCode that
  // store MCP servers under a different key (e.g. "mcp") to reuse the
  // existing JSON merge-patch adapter without a new action kind.
  mcpPatchKey?: string;
}

export interface UnsupportedAgentSurface {
  status: "unsupported";
  schemaLabel: string;
  reason: string;
}

/**
 * A surface that is confirmed as Copilot-specific and genuinely justified for
 * future dedicated implementation, but not yet supported. Distinct from
 * "unsupported" (which means the surface is either covered by another target or
 * will never be added) so adapters can emit a forward-looking "planned" notice
 * rather than a blocking skip warning.
 */
export interface PlannedAgentSurface {
  status: "planned";
  schemaLabel: string;
  /** Short description of the concrete file / config surface to be implemented. */
  plannedSurface: string;
  reason: string;
}

export type AgentSurfaceSupport =
  | SupportedAgentSurface
  | UnsupportedAgentSurface
  | PlannedAgentSurface;

export interface AgentProvenance {
  /** Omit when the agent has no separate skill deployment path. */
  skills?: Confidence;
  detectPaths: Confidence;
  detectBinary: Confidence;
  mcpConfig?: Confidence;
  agentRules?: Confidence;
  permissions?: Confidence;
  agentDefinitions?: Confidence;
}

export interface AgentConfig {
  id: AgentId;
  displayName: string;
  /**
   * The on-disk path template for deploying skills to this agent.
   * Omit for agents that consume skills from another agent's path natively
   * (e.g. GitHub Copilot reads `.claude/skills/` directly).
   */
  skills?: AgentPaths;
  /**
   * When `skills` is absent, this field explains why. Currently only
   * "shared-via" is used — the agent reads skills from the `via` agent's
   * deployment path natively and needs no separate skills deploy action.
   */
  skillsSurfaceKind?: { kind: "shared-via"; via: AgentId };
  detectPaths: AgentPaths;
  detectBinary: string | null;
  provenance: AgentProvenance;
  // Agent-specific MCP surface support. Unsupported entries are carried
  // explicitly so adapter warnings can explain whether support is blocked by
  // TOML, frontmatter, repo-scoped files, or other non-JSON schemas.
  mcpSupport?: AgentSurfaceSupport;
  // Agent-specific persistent instruction/rules surface support.
  agentRulesSupport?: AgentSurfaceSupport;
  // Repo-local instruction/rules surface (scope: "repo"). When absent, the
  // adapter falls back to agentRulesSupport (covers antigravity, which is
  // already repo-local).
  agentRulesRepoSupport?: AgentSurfaceSupport;
  // Workspace-local instruction/rules surface (scope: "workspace"). When absent,
  // the adapter handles it by failing or reporting unsupported.
  agentRulesWorkspaceSupport?: AgentSurfaceSupport;
  // Agent-specific execution/safety permission and approval surface support.
  permissionsSupport?: AgentSurfaceSupport;
  // Agent-specific agent/subagent definition file surface support.
  agentDefinitionsSupport?: AgentSurfaceSupport;
  policyNote?: string;
  /**
   * When true, instruction files deployed to this agent must include valid
   * YAML frontmatter. Drives validateInstructionFileRequirements without
   * hardcoded agent-ID checks.
   */
  instructionFrontmatterRequired?: boolean;
  /**
   * When true, preflight runs enterprise-policy detection for this agent.
   */
  enterprisePolicyDetection?: boolean;
}

export interface PlanWarning {
  kind: "confidence" | "collision" | "ambiguity";
  message: string;
}

export interface SkillDirDeployAction {
  kind: "skill-dir";
  skill: string;
  agent: AgentId;
  source: string;
  target: string;
  method: "symlink" | "copy";
  confidence: Confidence;
}

export interface FileWriteDeployAction {
  kind: "file-write";
  skill: string;
  agent: AgentId;
  source: string;
  target: string;
  confidence?: Confidence;
}

export interface ConfigPatchDeployAction {
  kind: "config-patch";
  skill: string;
  agent: AgentId;
  target: string;
  patch: unknown;
  confidence?: Confidence;
}

export interface TomlPatchDeployAction {
  kind: "toml-patch";
  skill: string;
  agent: AgentId;
  target: string;
  config: Record<string, unknown>;
  confidence?: Confidence;
}

export interface FrontmatterEmitDeployAction {
  kind: "frontmatter-emit";
  skill: string;
  agent: AgentId;
  // Absolute path to the .md file to create/update.
  target: string;
  // Key-value pairs to write into the YAML frontmatter block.
  frontmatter: Record<string, unknown>;
  confidence?: Confidence;
}

export type DeployAction =
  | SkillDirDeployAction
  | FileWriteDeployAction
  | ConfigPatchDeployAction
  | TomlPatchDeployAction
  | FrontmatterEmitDeployAction;

export interface SkillDirRevertAction {
  kind: "skill-dir";
  skill: string;
  agent: AgentId;
  target: string;
}

export interface FileWriteRevertAction {
  kind: "file-write";
  skill: string;
  agent: AgentId;
  target: string;
}

export interface ConfigPatchRevertAction {
  kind: "config-patch";
  skill: string;
  agent: AgentId;
  target: string;
}

export interface TomlPatchRevertAction {
  kind: "toml-patch";
  skill: string;
  agent: AgentId;
  target: string;
}

export interface FrontmatterEmitRevertAction {
  kind: "frontmatter-emit";
  skill: string;
  agent: AgentId;
  target: string;
}

export type RevertAction =
  | SkillDirRevertAction
  | FileWriteRevertAction
  | ConfigPatchRevertAction
  | TomlPatchRevertAction
  | FrontmatterEmitRevertAction;

export type PlannedChangeVerb =
  | "create-symlink"
  | "copy-dir"
  | "write-file"
  | "patch-config"
  | "patch-toml"
  | "emit-frontmatter"
  | "remove"
  | "unapply-patch";

export interface PlannedChange {
  verb: PlannedChangeVerb;
  kind:
    | "skill-dir"
    | "file-write"
    | "config-patch"
    | "toml-patch"
    | "frontmatter-emit";
  skill: string;
  agent: AgentId;
  source?: string;
  target: string;
  method?: "symlink" | "copy";
  patch?: Record<string, unknown>;
  frontmatter?: Record<string, unknown>;
  confidence?: Confidence;
}

export interface CliOptions {
  command: "deploy" | "revert" | "init" | "help";
  directory: string;
  dryRun: boolean;
  agents: AgentId[] | null;
  verbose: boolean;
  debug: boolean;
  force: boolean;
}

import path from "node:path";
import type { AgentDefinitionEntry } from "../../schemas/manifest.ts";
import type {
  AgentId,
  FileWriteDeployAction,
  FileWriteRevertAction,
  PlanWarning,
} from "../../types.ts";
import {
  planCapabilityForDeploy,
  resolveCapabilitySurface,
} from "../capabilities.ts";
import { getPlatformKey, resolvePlaceholders } from "../resolve.ts";
import {
  validateAgentRuleMarkdownPath,
  validateInstructionFileRequirements,
  validateSourceFile,
  validateSourcePath,
} from "../validation.ts";

export interface AgentDefinitionsAdapterResult {
  actions: FileWriteDeployAction[];
  warnings: PlanWarning[];
}

/**
 * Compiles deploy actions for agentDefinitions manifest entries.
 *
 * Agent definition files are Markdown files (typically with YAML frontmatter)
 * that define custom agents or subagents for a given platform. Unlike
 * agentRules (which target a single shared global file per agent), each
 * definition entry produces a separate file named after the entry in the
 * agent's dedicated agent-definitions directory (repo-local).
 *
 * Target paths use the `{repo}` placeholder so definitions land in the
 * repository being deployed, not the user's home directory.
 */
export async function compileAgentDefinitionActions(
  entry: AgentDefinitionEntry,
  sourceDir: string,
  resolvedSourceDir: string,
  realRoot: string,
  detectedAgents: AgentId[],
  home: string,
  repo?: string,
  workspace?: string,
): Promise<AgentDefinitionsAdapterResult> {
  const actions: FileWriteDeployAction[] = [];
  const warnings: PlanWarning[] = [];
  const platform = getPlatformKey();
  const targetAgents = entry.agents.filter((agentId) =>
    detectedAgents.includes(agentId),
  );
  const supportedTargets: Array<{
    agentId: AgentId;
    confidence: FileWriteDeployAction["confidence"];
    target: string;
  }> = [];

  if (targetAgents.length === 0) {
    return { actions, warnings };
  }

  for (const agentId of targetAgents) {
    const plan = planCapabilityForDeploy({
      agentId,
      capability: "agentDefinitions",
      entryName: entry.name,
      targetAgentIds: targetAgents,
    });
    if (plan.outcome === "warn") {
      warnings.push(plan.warning);
      continue;
    }
    if (plan.outcome === "native" || plan.outcome === "redundant") continue;

    const support = resolveCapabilitySurface(
      agentId,
      "agentDefinitions",
    ).support;
    if (!support) continue;

    supportedTargets.push({
      agentId,
      confidence: plan.confidence ?? "provisional",
      target: resolvePlaceholders(
        support.path[platform],
        entry.name,
        home,
        repo,
        workspace,
      ),
    });
  }

  if (supportedTargets.length === 0) {
    return { actions, warnings };
  }

  // Validate the shared source file only when at least one target is active.
  const source = path.resolve(sourceDir, entry.path);
  await validateSourcePath(source, entry.path, resolvedSourceDir, realRoot);
  await validateSourceFile(source, entry.path);

  for (const target of supportedTargets) {
    validateAgentRuleMarkdownPath(entry.path, target.agentId);
    await validateInstructionFileRequirements(
      source,
      entry.path,
      target.agentId,
    );
    actions.push({
      kind: "file-write",
      skill: entry.name,
      agent: target.agentId,
      source,
      target: target.target,
      confidence: target.confidence,
    });
  }

  return { actions, warnings };
}

export function compileAgentDefinitionReverts(
  entry: AgentDefinitionEntry,
  agentFilter: AgentId[] | null,
  home: string,
  repo?: string,
  workspace?: string,
): FileWriteRevertAction[] {
  const actions: FileWriteRevertAction[] = [];
  const platform = getPlatformKey();

  for (const agentId of entry.agents) {
    if (agentFilter && !agentFilter.includes(agentId)) continue;
    const support = resolveCapabilitySurface(
      agentId,
      "agentDefinitions",
    ).support;
    if (!support) continue;
    const target = resolvePlaceholders(
      support.path[platform],
      entry.name,
      home,
      repo,
      workspace,
    );
    actions.push({
      kind: "file-write",
      skill: entry.name,
      agent: agentId,
      target,
    });
  }
  return actions;
}

